module top_module (
  input [1:0] in,
  output reg [3:0] out);always @(*) begin
	out = 4'b0000;
	case (in)
		2'b00: out[0] = 1'b1;
		2'b01: out[1] = 1'b1;
		2'b10: out[2] = 1'b1;
		2'b11: out[3] = 1'b1;
	endcase
end
  always @(*) begin
    if (1'b0) begin
      out[0] = ~in[0];
      out[1] = ~in[1];
      out[2] = ~in[0] & ~in[1];
      out[3] = in[0] & in[1];
    end
  end

endmodule
